import requests
from concurrent.futures import ThreadPoolExecutor, as_completed

base = 'http://localhost:5003'
paths = [
    '/auth', '/auth/login', '/auth/register', '/docs', '/swagger', '/openapi.json', '/whoami', '/session', '/sessions',
    '/metrics', '/upload', '/uploads', '/read', '/view', '/calc', '/evaluate', '/render', '/search', '/query',
    '/redirect', '/avatar', '/image', '/img', '/thumbnail', '/proxy', '/fetch', '/internal', '/settings', '/source', '/src', '/env', '/sqlite', '/database', '/backup', '/console'
]

results = []
with ThreadPoolExecutor(max_workers=8) as ex:
    futures = {ex.submit(requests.get, base+p, allow_redirects=False, timeout=5): p for p in paths}
    for fut in as_completed(futures):
        p = futures[fut]
        try:
            r = fut.result()
            results.append((p, r.status_code, r.headers.get('Location'), r.headers.get('Content-Type'), len(r.content)))
        except Exception as e:
            results.append((p, 'ERR', str(e), None, 0))

for row in sorted(results):
    print(row)
